import { CCol, CForm, CFormInput, CContainer, CRow, CFormLabel } from '@coreui/react';
import React from 'react';
import TextArea from '../common/TextArea';
import CIcon from '@coreui/icons-react';
import { cilPlus } from '@coreui/icons';

const MagazineComponent = () => {
    return (
        <CContainer className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
            <CRow className="w-90" >
                <CCol md={12}>
                    <CFormLabel htmlFor="formFile">Title<span className="text-danger">*</span></CFormLabel>
                    <CForm>
                        <CFormInput
                            id="exampleFormControlInput1"
                            placeholder=""
                        />
                    </CForm>
                </CCol>
                <CCol md={12} >
                    <TextArea
                        value=""
                        label="Article"
                        required
                        name={"article"}
                    />
                </CCol>
                <CCol md={12}>
                    <CFormInput type="file" size="lg" id="formFileLg" label="Large file input example" />
                </CCol>
            </CRow>
        </CContainer>
    );
};

export default MagazineComponent;
